function Search() {
  const [query, setQuery] = useState('');
  const [filtered, setFiltered] = useState(data);

  const handleChange = e => {
    const value = e.target.value;
    setQuery(value); // 🔹 срочное обновление — текст в input меняется мгновенно

    startTransition(() => {
      setFiltered(filterItems(data, value)); // 🔹 низкоприоритетное обновление
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      <List items={filtered} />
    </>
